using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
string strmax(string s1, string s2)
{
	string str1 = s1, str2 = s2;
	for (int i = 0; i < (int)s1.size(); i++)
	{
		str1[i] = tolower(str1[i]);
	}
	for (int i = 0; i < (int)s2.size(); i++)
	{
		str2[i] = tolower(str2[i]);
	}
	return (str1 > str2) ? s1 : s2;
}

CI MAXN = 1e5 + 5;
int n, m, x, y, a[MAXN], o[MAXN];
string f[MAXN][22];
int main(void)
{
	n = read(), m = read(), o[1] = 0;
	for (int i = 2; i <= n; ++i)
	{
		o[i] = o[i >> 1] + 1;
	}
	for (int i = 1; i <= n; ++i)
	{
		cin >> f[i][0];
	}
	for (int j = 1; j <= o[n]; j++)
	{
		for (int i = 1; i <= n - (1 << j) + 1; ++i)
		{
			f[i][j] = strmax(f[i][j - 1], f[i + (1 << (j - 1))][j - 1]);
		}
	}
	for (int i = 1; i <= m; ++i)
	{
		x = read(), y = read();
		int l = o[y - x + 1];
		cout << strmax(f[x][l], f[y - (1 << l) + 1][l]) << "\n";
	}
	return false;
}
